var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"괘, 괜찮아?! 컵이 깨졌잖아!","JPN":"だ、大丈夫！？　コップが割れてるじゃない！","ENG":"A-are you okay? The cup broke!","TWN":"沒事吧？杯子碎了！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"다치진 않았어?","JPN":"怪我はしてない？","ENG":"Did you hurt yourself?","TWN":"妳沒受傷吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"......이건!","JPN":"……これは！","ENG":"Could this be...","TWN":"……這是！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"컵이 저절로 깨지다니, 역시 이건 불길한 신탁인가?","JPN":"コップが自然に割れるなんて、何か不吉な神託でしょうか？","ENG":"The cup just shattered on its own. Is this some kind of ominous omen?","TWN":"杯子竟然會自己碎掉了，這果然是什麼不吉利的徵兆嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"대흉 같은 게 밀려올 징조인 건가?!","JPN":"悪運が一気に押し寄せる兆候なのでしょうか！？","ENG":"A sign of something terrible to come?!","TWN":"比如說凶邪之物即將降臨的徵兆嗎？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"무슨 바보 같은 말이죠? 당연히 이 컵이 불량품이란 뜻이죠.","JPN":"なにバカげたこと言ってるの？　このコップが不良品だってことでしょ。","ENG":"Don't be ridiculous. It just means the cup was faulty.","TWN":"妳在說什麼傻話？ 當然是因為這個杯子是瑕疵品啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"컵이 깨졌다고 불행이 닥치다니 그런 미신 같은 소리가 어디 있나요?","JPN":"コップが割れたから不幸が起きるだなんて、そんな迷信じみたことをよくもまあ言えたものね。","ENG":"You thought this was some kind of an omen? How superstitious of you.","TWN":"因為杯子碎了，所以不幸就會降臨，哪有這種迷信的事情啊？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"한─심하네요, 레나 양.","JPN":"情けないったらありゃしない。","ENG":"That’s pretty pathetic, Lena.","TWN":"真不敢相信妳會有這種愚蠢想法，蕾娜小姐。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"사이비 종교 같은 곳에 끌려가지 않도록 주의하셔야겠어요.","JPN":"えせ宗教みたいなところに連れて行かれないように、よーく気をつけてよね。","ENG":"You’d better be careful you don’t end up in some kind of cult.","TWN":"妳要小心不要被騙進那種邪教組織喔。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그럼 전 이만.","JPN":"じゃあ、私はこれで。","ENG":"Bye now.","TWN":"那我就先走了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"야! 너! 내가! 어?! 그러니까, 와 진짜! 거기 서! 야!","JPN":"ねえ！　あんた！　私が！　はあ！？　ねえ、ホント！　待ちなさい！　待ちなさいってば！","ENG":"Hey! You! Come on! Seriously?! You've got to be kidding me! Stop right there! Hey!","TWN":"喂！妳這傢伙！妳在說什麼啦？真是的！給我站住！喂！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서, 우린 지금 어디로 가고 있는 거지?","JPN":"それで、私たちは今どこに向かってるの？","ENG":"So, where are we headed?","TWN":"所以，我們現在要去哪裡啊？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"굉장히 철학적인 질문이네요.","JPN":"とても哲学的な質問ですね。","ENG":"That’s a very philosophical question.","TWN":"嗯，這是個哲學的問題呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 현실적인 의미로 대답하자면, 음.......","JPN":"ですが、現実的な意味で答えると、そうですねえ……","ENG":"But to give you a more literal answer, hmm...","TWN":"但如果按照實際情況來回答妳的話，嗯……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이면세계의 차원 단층 사이를 아슬아슬하게 날고 있다고 할 수 있겠네요.","JPN":"カウンターサイドの次元断層の間をスレスレに飛んでいると言えますかね。","ENG":"I'd say we’re flying precariously between the dimensional strata of the Counterside.","TWN":"可以說，我們正在異界的次元斷層間驚險地飛行。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......온몸에 벌레가 기어다니는 것 같아.","JPN":"……全身に虫が這っているみたい。","ENG":"I feel like there are bugs crawling all over my body.","TWN":"……我全身好像有蟲子在爬一樣。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};